import React from 'react';
import IconButton from '@mui/material/IconButton';

const FAWImageButton = ({ src, alt, onClick, sx, ...rest }) => (
  <IconButton onClick={onClick} sx={sx} {...rest}>
    <img src={src} alt={alt} style={{ width: 24, height: 24 }} />
  </IconButton>
);

export default FAWImageButton; 